import { Request, Response, NextFunction } from 'express';
import { GroupService } from './group.service';
import { GroupValidator } from './group.validator';
import { CreateGroupDTO, LinkTelegramDTO } from './group.dto';

export class GroupController {
  private groupService: GroupService;

  constructor(groupService: GroupService) {
    this.groupService = groupService;
  }

  public async createGroup(req: Request, res: Response, next: NextFunction) {
    try {
      const inputData: CreateGroupDTO = GroupValidator.validateCreateGroup(req.body);
      const group = await this.groupService.createGroup(inputData, req.user.id);
      res.status(201).json({ success: true, data: group, meta: { requestId: req.id, timestamp: new Date().toISOString(), version: 'v1' } });
    } catch (error) {
      next(error);
    }
  }

  public async getGroup(req: Request, res: Response, next: NextFunction) {
    try {
      const groupId = req.params.id;
      const group = await this.groupService.getGroupById(groupId);
      res.json({ success: true, data: group, meta: { requestId: req.id, timestamp: new Date().toISOString(), version: 'v1' } });
    } catch (error) {
      next(error);
    }
  }

  public async linkTelegram(req: Request, res: Response, next: NextFunction) {
    try {
      const groupId = req.params.id;
      const telegramData: LinkTelegramDTO = GroupValidator.validateLinkTelegram(req.body);
      await this.groupService.linkTelegram(groupId, telegramData);
      res.json({ success: true, message: 'Telegram chat linked successfully.', meta: { requestId: req.id, timestamp: new Date().toISOString(), version: 'v1' } });
    } catch (error) {
      next(error);
    }
  }
}

import { GroupRepository } from './group.repository';
import { CreateGroupDTO, LinkTelegramDTO } from './group.dto';
import { AppError } from '../../utils/app-error';
import { ObjectId } from 'mongodb';

export class GroupService {
  private groupRepository: GroupRepository;

  constructor(groupRepository: GroupRepository) {
    this.groupRepository = groupRepository;
  }

  public async createGroup(data: CreateGroupDTO, adminId: ObjectId) {
    if (await this.groupRepository.isGroupNameTaken(data.name)) {
      throw new AppError('Group name is already taken', 'GROUP_NAME_TAKEN', 400);
    }
    const group = await this.groupRepository.createGroup({ ...data, adminId, createdAt: new Date() });
    return group;
  }

  public async getGroupById(groupId: string) {
    const group = await this.groupRepository.getGroupById(new ObjectId(groupId));
    if (!group) {
      throw new AppError('Group not found', 'GROUP_NOT_FOUND', 404);
    }
    return group;
  }

  public async linkTelegram(groupId: string, telegramData: LinkTelegramDTO) {
    const result = await this.groupRepository.linkTelegram(new ObjectId(groupId), telegramData.telegramChatId);
    if (!result.modifiedCount) {
      throw new AppError('Failed to link Telegram chat', 'FAILED_LINK_TELEGRAM', 400);
    }
  }
}

import { ObjectId } from 'mongodb';
import { GroupModel } from './group.model';

export class GroupRepository {
  public async isGroupNameTaken(name: string): Promise<boolean> {
    const count = await GroupModel.countDocuments({ name });
    return count > 0;
  }

  public async createGroup(group: Partial<GroupModel>): Promise<GroupModel> {
    const newGroup = new GroupModel(group);
    return newGroup.save();
  }

  public async getGroupById(groupId: ObjectId): Promise<GroupModel | null> {
    return GroupModel.findById(groupId).exec();
  }

  public async linkTelegram(groupId: ObjectId, telegramChatId: string) {
    return GroupModel.updateOne({ _id: groupId }, { $set: { telegramChatId } }).exec();
  }
}

import { Schema, model } from 'mongoose';

const GroupSchema = new Schema({
  name: { type: String, required: true },
  description: { type: String, required: true },
  adminId: { type: Schema.Types.ObjectId, required: true, ref: 'User' },
  members: [{ type: Schema.Types.ObjectId, ref: 'User' }],
  telegramChatId: { type: String },
  createdAt: { type: Date, default: Date.now }
});

export const GroupModel = model('Group', GroupSchema);

export interface CreateGroupDTO {
  name: string;
  description: string;
}

export interface LinkTelegramDTO {
  telegramChatId: string;
}

import { z } from 'zod';
import { CreateGroupDTO, LinkTelegramDTO } from './group.dto';

const createGroupSchema = z.object({
  name: z.string().min(2),
  description: z.string().min(5)
});

const linkTelegramSchema = z.object({
  telegramChatId: z.string().min(5)
});

export class GroupValidator {
  public static validateCreateGroup(data: any): CreateGroupDTO {
    return createGroupSchema.parse(data);
  }

  public static validateLinkTelegram(data: any): LinkTelegramDTO {
    return linkTelegramSchema.parse(data);
  }
}
